#!/usr/bin/env bash
set -euo pipefail

VERSION="5.4.1"

# --- Skill registry ---
# Each skill: name, description, file count, and file declarations
SKILL_COUNT=4
SKILL_1_NAME="css-spring"
SKILL_1_DESC=" Generate CSS springs as linear() easing curves and durations. Triggers: css spring, spring easing, linear(), bounce, cs"
SKILL_1_FILE_1_PATH="/SKILL.md"
SKILL_1_FILE_1_B64=""
SKILL_1_FILE_COUNT=1
SKILL_2_NAME="motion-audit"
SKILL_2_DESC=" Animation performance audit tool for CSS & Motion. Ranks animations S-through-F based on render pipeline cost: composit"
SKILL_2_FILE_1_PATH="/SKILL.md"
SKILL_2_FILE_1_B64=""
SKILL_2_FILE_2_PATH="/references/property-tiers.json"
SKILL_2_FILE_2_B64=""
SKILL_2_FILE_3_PATH="/tier-reference.md"
SKILL_2_FILE_3_B64=""
SKILL_2_FILE_COUNT=3
SKILL_3_NAME="motion"
SKILL_3_DESC=" Platform-specific guidance for Motion (vanilla JS, React, Vue) including documentation search, import patterns, perform"
SKILL_3_FILE_1_PATH="/SKILL.md"
SKILL_3_FILE_1_B64=""
SKILL_3_FILE_2_PATH="/base-ui.md"
SKILL_3_FILE_2_B64=""
SKILL_3_FILE_3_PATH="/motion.md"
SKILL_3_FILE_3_B64=""
SKILL_3_FILE_4_PATH="/react.md"
SKILL_3_FILE_4_B64=""
SKILL_3_FILE_5_PATH="/vue.md"
SKILL_3_FILE_5_B64=""
SKILL_3_FILE_COUNT=5
SKILL_4_NAME="see-transition"
SKILL_4_DESC=" Visualise CSS easings and Motion transitions. Triggers on: see, visualise"
SKILL_4_FILE_1_PATH="/SKILL.md"
SKILL_4_FILE_1_B64=""
SKILL_4_FILE_COUNT=1

# --- Color output (only when stdout is a TTY) ---
if [ -t 1 ]; then
  BOLD="\033[1m"
  GREEN="\033[32m"
  RED="\033[31m"
  DIM="\033[2m"
  YELLOW="\033[33m"
  RESET="\033[0m"
else
  BOLD="" GREEN="" RED="" DIM="" YELLOW="" RESET=""
fi

ok() { printf "  ${GREEN}✓${RESET} %s\n" "$1"; }

# Build selection state (all pre-selected)
declare -a selected
for i in $(seq 1 "$SKILL_COUNT"); do
  selected[$i]=1
done

# Show picker (only if stdin is a TTY)
if [ -t 0 ]; then
  show_menu() {
    clear
    printf "\n${BOLD}Motion AI Kit v${VERSION}${RESET}\n\n"
    printf "Select skills to install (toggle with number, Enter to confirm):\n\n"
    local i=1
    while [ "$i" -le "$SKILL_COUNT" ]; do
      local name_var="SKILL_${i}_NAME"
      local name="${!name_var}"
      if [ "${selected[$i]}" -eq 1 ]; then
        printf "  ${DIM}(%d)${RESET} ${GREEN}[x]${RESET} ${BOLD}%s${RESET}\n" "$i" "$name"
      else
        printf "  ${DIM}(%d) [ ] %s${RESET}\n" "$i" "$name"
      fi
      i=$((i + 1))
    done
    printf "\n"
  }

  show_menu

  while true; do
    IFS= read -rsn1 key
    if [ "$key" = "" ]; then
      break
    elif [[ "$key" =~ ^[0-9]$ ]] && [ "$key" -ge 1 ] && [ "$key" -le "$SKILL_COUNT" ]; then
      if [ "${selected[$key]}" -eq 1 ]; then
        selected[$key]=0
      else
        selected[$key]=1
      fi
      show_menu
    fi
  done
  printf "\n"
else
  # Non-interactive: install all
  printf "\n${BOLD}Motion AI Kit v${VERSION}${RESET}\n\n"
  printf "Installing all skills (non-interactive mode)\n\n"
fi

# Check if anything selected
any_selected=0
for i in $(seq 1 "$SKILL_COUNT"); do
  if [ "${selected[$i]}" -eq 1 ]; then
    any_selected=1
    break
  fi
done

if [ "$any_selected" -eq 0 ]; then
  printf "${YELLOW}No skills selected. Nothing to install.${RESET}\n\n"
  exit 0
fi

# --- Detect tools ---
declare -a tools=()
declare -a tool_dirs=()

detect_tool() {
  local name="$1"
  local dir="$2"
  if [ -d "$dir" ]; then
    tools+=("$name")
    tool_dirs+=("$dir")
  fi
}

detect_tool "Claude Code" "${HOME}/.claude"
detect_tool "Cursor" "${HOME}/.cursor"
detect_tool "Amp" "${HOME}/.amp"
detect_tool "OpenCode" "${HOME}/.opencode"
detect_tool "Gemini CLI" "${HOME}/.gemini"
detect_tool "Codex" "${CODEX_HOME:-${HOME}/.codex}"

has_windsurf=0
if [ -d "${HOME}/.windsurf" ]; then
  has_windsurf=1
fi

if [ ${#tools[@]} -eq 0 ] && [ "$has_windsurf" -eq 0 ]; then
  printf "${RED}No supported tools detected.${RESET}\n"
  printf "${DIM}Supported: Codex, Claude Code, Cursor, Amp, OpenCode, Gemini CLI, Windsurf${RESET}\n\n"
  exit 1
fi

# --- Install functions ---
install_skill_files() {
  local skill_idx="$1"
  local target_dir="$2"

  local name_var="SKILL_${skill_idx}_NAME"
  local fcount_var="SKILL_${skill_idx}_FILE_COUNT"
  local skill_name="${!name_var}"
  local file_count="${!fcount_var}"
  local skill_dir="${target_dir}/skills/${skill_name}"

  local j=1
  while [ "$j" -le "$file_count" ]; do
    local path_var="SKILL_${skill_idx}_FILE_${j}_PATH"
    local data_var="SKILL_${skill_idx}_FILE_${j}_B64"
    local rel_path="${!path_var}"
    local file_data="${!data_var}"
    local full_path="${skill_dir}/${rel_path}"

    mkdir -p "$(dirname "$full_path")"
    echo "$file_data" | base64 -d > "$full_path"
    j=$((j + 1))
  done
}

install_windsurf_skill() {
  local skill_idx="$1"
  local rules_file="${HOME}/.windsurf/global_rules.md"

  local name_var="SKILL_${skill_idx}_NAME"
  local fcount_var="SKILL_${skill_idx}_FILE_COUNT"
  local skill_name="${!name_var}"
  local file_count="${!fcount_var}"
  local marker="<!-- ${skill_name}-skill -->"

  # Decode and concatenate all files
  local combined=""
  local j=1
  while [ "$j" -le "$file_count" ]; do
    local path_var="SKILL_${skill_idx}_FILE_${j}_PATH"
    local data_var="SKILL_${skill_idx}_FILE_${j}_B64"
    local rel_path="${!path_var}"
    local content
    content=$(echo "${!data_var}" | base64 -d)

    if [ -n "$combined" ]; then
      combined="${combined}

---

"
    fi
    combined="${combined}<!-- ${rel_path} -->
${content}"
    j=$((j + 1))
  done

  local block
  block=$(cat <<BLOCK
${marker}
# ${skill_name} Skill

${combined}
${marker}
BLOCK
)

  if [ -f "$rules_file" ]; then
    if grep -qF "$marker" "$rules_file" 2>/dev/null; then
      local tmp
      tmp=$(mktemp)
      awk -v m="$marker" '
        BEGIN { skip=0 }
        $0 == m { skip = !skip; next }
        !skip { print }
      ' "$rules_file" > "$tmp"
      cat "$tmp" > "$rules_file"
      rm "$tmp"
    fi
  fi

  mkdir -p "$(dirname "$rules_file")"
  printf "\n%s\n" "$block" >> "$rules_file"
}

# --- Install selected skills to each detected tool ---
total_installed=0

for t in $(seq 0 $((${#tools[@]} - 1))); do
  tool_name="${tools[$t]}"
  tool_dir="${tool_dirs[$t]}"
  printf "${BOLD}%s${RESET}\n" "$tool_name"

  for i in $(seq 1 "$SKILL_COUNT"); do
    if [ "${selected[$i]}" -eq 1 ]; then
      name_var="SKILL_${i}_NAME"
      install_skill_files "$i" "$tool_dir"
      ok "${!name_var}"
    fi
  done
  total_installed=$((total_installed + 1))
  printf "\n"
done

# Windsurf
if [ "$has_windsurf" -eq 1 ]; then
  printf "${BOLD}Windsurf${RESET}\n"
  for i in $(seq 1 "$SKILL_COUNT"); do
    if [ "${selected[$i]}" -eq 1 ]; then
      name_var="SKILL_${i}_NAME"
      install_windsurf_skill "$i"
      ok "${!name_var}"
    fi
  done
  total_installed=$((total_installed + 1))
  printf "\n"
fi

# --- Summary ---
selected_count=0
for i in $(seq 1 "$SKILL_COUNT"); do
  if [ "${selected[$i]}" -eq 1 ]; then
    selected_count=$((selected_count + 1))
  fi
done

printf "${DIM}Done! Installed ${selected_count} skill(s) to ${total_installed} tool(s).${RESET}\n\n"
